import React from 'react';
import { Plus, Target, Calendar, Flame, TrendingUp } from 'lucide-react';
import BottomNav from '../components/BottomNav';
import { goals } from '../data/mockData';

const Goals: React.FC = () => {
  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <div className="bg-gradient-to-br from-cyan-500 to-cyan-600 text-white px-4 pt-8 pb-20">
        <div className="max-w-md mx-auto flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold mb-1">我的目标</h1>
            <p className="text-cyan-100">设定目标，持续进步</p>
          </div>
          <button className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center hover:bg-white/30 transition-colors">
            <Plus className="w-6 h-6" />
          </button>
        </div>
      </div>

      <div className="px-4 -mt-12">
        <div className="max-w-md mx-auto">
          <div className="bg-white rounded-2xl p-6 shadow-lg mb-6">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-cyan-100 rounded-xl flex items-center justify-center">
                  <Target className="w-6 h-6 text-cyan-600" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-gray-800">
                    {goals.filter((g) => g.current >= g.target).length}/{goals.length}
                  </p>
                  <p className="text-sm text-gray-500">已完成目标</p>
                </div>
              </div>
            </div>
            <div className="w-full bg-gray-100 rounded-full h-2">
              <div
                className="bg-gradient-to-r from-cyan-500 to-cyan-400 rounded-full h-2"
                style={{
                  width: `${
                    (goals.filter((g) => g.current >= g.target).length / goals.length) * 100
                  }%`,
                }}
              />
            </div>
          </div>

          <div className="space-y-4">
            {goals.map((goal) => {
              const progress = (goal.current / goal.target) * 100;
              const isCompleted = goal.current >= goal.target;

              const getIcon = (title: string) => {
                if (title.includes('训练')) return <Calendar className="w-6 h-6" />;
                if (title.includes('卡路里')) return <Flame className="w-6 h-6" />;
                if (title.includes('连续')) return <TrendingUp className="w-6 h-6" />;
                return <Target className="w-6 h-6" />;
              };

              const getColor = (title: string) => {
                if (title.includes('训练')) return 'cyan';
                if (title.includes('卡路里')) return 'orange';
                if (title.includes('连续')) return 'purple';
                return 'green';
              };

              const color = getColor(goal.title);
              const colorClasses = {
                cyan: {
                  bg: 'bg-cyan-100',
                  text: 'text-cyan-600',
                  bar: 'from-cyan-500 to-cyan-400',
                },
                orange: {
                  bg: 'bg-orange-100',
                  text: 'text-orange-600',
                  bar: 'from-orange-500 to-orange-400',
                },
                purple: {
                  bg: 'bg-purple-100',
                  text: 'text-purple-600',
                  bar: 'from-purple-500 to-purple-400',
                },
                green: {
                  bg: 'bg-green-100',
                  text: 'text-green-600',
                  bar: 'from-green-500 to-green-400',
                },
              };

              return (
                <div
                  key={goal.id}
                  className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100"
                >
                  <div className="flex items-start justify-between mb-4">
                    <div className="flex items-center gap-4">
                      <div
                        className={`w-12 h-12 ${colorClasses[color].bg} rounded-xl flex items-center justify-center ${colorClasses[color].text}`}
                      >
                        {getIcon(goal.title)}
                      </div>
                      <div>
                        <h3 className="font-medium text-gray-800">{goal.title}</h3>
                        <p className="text-sm text-gray-500">截止 {goal.deadline}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-2xl font-bold text-gray-800">
                        {goal.current}
                        <span className="text-sm text-gray-400 font-normal">/{goal.target}</span>
                        <span className="text-sm text-gray-400 font-normal ml-1">{goal.unit}</span>
                      </p>
                    </div>
                  </div>
                  <div className="w-full bg-gray-100 rounded-full h-3 mb-2">
                    <div
                      className={`bg-gradient-to-r ${colorClasses[color].bar} rounded-full h-3 transition-all duration-500`}
                      style={{ width: `${Math.min(progress, 100)}%` }}
                    />
                  </div>
                  <div className="flex items-center justify-between">
                    <span className="text-sm text-gray-500">{Math.round(progress)}% 已完成</span>
                    {isCompleted && (
                      <span className="text-sm font-medium text-green-500">已达成！</span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          <button className="w-full mt-6 bg-gray-100 text-gray-600 py-4 rounded-xl font-medium hover:bg-gray-200 transition-colors flex items-center justify-center gap-2">
            <Plus className="w-5 h-5" />
            添加新目标
          </button>
        </div>
      </div>

      <BottomNav />
    </div>
  );
};

export default Goals;
