import React from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import {
  ArrowLeft,
  Clock,
  Flame,
  Star,
  Play,
  ChevronRight,
  Heart,
  Share2,
} from 'lucide-react';
import BottomNav from '../components/BottomNav';
import { courses } from '../data/mockData';

const CourseDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const course = courses.find((c) => c.id === id);

  if (!course) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <p className="text-gray-500 mb-4">课程不存在</p>
          <Link to="/courses" className="text-cyan-500 font-medium">
            返回课程列表
          </Link>
        </div>
      </div>
    );
  }

  const difficultyLabels = {
    beginner: '初级',
    intermediate: '中级',
    advanced: '高级',
  };

  const difficultyColors = {
    beginner: 'bg-green-100 text-green-700',
    intermediate: 'bg-yellow-100 text-yellow-700',
    advanced: 'bg-red-100 text-red-700',
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-24">
      <div className="relative">
        <img
          src={course.image}
          alt={course.title}
          className="w-full h-64 object-cover"
        />
        <div className="absolute top-0 left-0 right-0 p-4">
          <div className="max-w-md mx-auto flex items-center justify-between">
            <button
              onClick={() => navigate(-1)}
              className="p-2 bg-white/20 backdrop-blur rounded-full"
            >
              <ArrowLeft className="w-6 h-6 text-white" />
            </button>
            <div className="flex gap-2">
              <button className="p-2 bg-white/20 backdrop-blur rounded-full">
                <Heart className="w-6 h-6 text-white" />
              </button>
              <button className="p-2 bg-white/20 backdrop-blur rounded-full">
                <Share2 className="w-6 h-6 text-white" />
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="px-4 -mt-6">
        <div className="max-w-md mx-auto">
          <div className="bg-white rounded-2xl p-6 shadow-lg">
            <div className="flex items-start justify-between mb-4">
              <div>
                <span
                  className={`inline-block px-3 py-1 rounded-full text-xs font-medium mb-2 ${difficultyColors[course.difficulty]}`}
                >
                  {difficultyLabels[course.difficulty]}
                </span>
                <h1 className="text-2xl font-bold text-gray-800 mb-2">
                  {course.title}
                </h1>
                <p className="text-gray-500">{course.description}</p>
              </div>
            </div>

            <div className="flex items-center gap-6 py-4 border-y border-gray-100 mb-4">
              <div className="flex items-center gap-2">
                <Clock className="w-5 h-5 text-cyan-500" />
                <span className="text-sm text-gray-600">{course.duration}</span>
              </div>
              <div className="flex items-center gap-2">
                <Flame className="w-5 h-5 text-orange-500" />
                <span className="text-sm text-gray-600">{course.calories}千卡</span>
              </div>
              <div className="flex items-center gap-2">
                <Star className="w-5 h-5 text-yellow-400 fill-yellow-400" />
                <span className="text-sm text-gray-600">{course.rating}</span>
              </div>
            </div>

            <div className="flex items-center justify-between">
              <div>
                {course.price ? (
                  <>
                    <span className="text-xs text-gray-400 line-through">
                      ¥{course.price + 100}
                    </span>
                    <span className="text-2xl font-bold text-cyan-500 ml-2">
                      ¥{course.price}
                    </span>
                  </>
                ) : (
                  <span className="text-2xl font-bold text-green-500">免费</span>
                )}
              </div>
            </div>
          </div>

          <div className="mt-6 mb-6">
            <h2 className="text-lg font-bold text-gray-800 mb-4">课程内容</h2>
            <div className="space-y-3">
              {course.exercises.map((exercise, index) => (
                <div
                  key={exercise.id}
                  className="bg-white rounded-xl p-4 shadow-sm border border-gray-100 flex items-center gap-4"
                >
                  <div className="w-12 h-12 bg-cyan-100 rounded-lg flex items-center justify-center flex-shrink-0">
                    <span className="text-cyan-600 font-bold">{index + 1}</span>
                  </div>
                  <img
                    src={exercise.image}
                    alt={exercise.name}
                    className="w-16 h-16 rounded-lg object-cover flex-shrink-0"
                  />
                  <div className="flex-1 min-w-0">
                    <h3 className="font-medium text-gray-800 truncate">
                      {exercise.name}
                    </h3>
                    <p className="text-sm text-gray-500">
                      {exercise.duration}
                      {exercise.reps && ` · ${exercise.reps}次`}
                    </p>
                  </div>
                  <Play className="w-5 h-5 text-gray-400 flex-shrink-0" />
                </div>
              ))}
            </div>
          </div>

          <div className="bg-gradient-to-br from-cyan-50 to-blue-50 rounded-2xl p-6 mb-6">
            <div className="flex items-start gap-3">
              <div className="w-10 h-10 bg-cyan-500 rounded-full flex items-center justify-center flex-shrink-0">
                <span className="text-white text-lg">💡</span>
              </div>
              <div>
                <h3 className="font-medium text-gray-800 mb-1">训练提示</h3>
                <p className="text-sm text-gray-600">
                  训练前请充分热身，训练过程中保持正确姿势，注意呼吸节奏。如有不适请立即停止。
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-4 py-4 z-50">
        <div className="max-w-md mx-auto">
          <Link
            to="/workout"
            className="w-full bg-gradient-to-r from-cyan-500 to-cyan-600 text-white py-4 rounded-xl font-bold text-lg shadow-lg hover:shadow-xl transition-shadow flex items-center justify-center gap-2"
          >
            <Play className="w-6 h-6 fill-current" />
            开始训练
          </Link>
        </div>
      </div>

      <BottomNav />
    </div>
  );
};

export default CourseDetails;
