import React from 'react';
import { Calendar, CheckCircle2, Clock, Flame } from 'lucide-react';
import BottomNav from '../components/BottomNav';
import { workoutRecords } from '../data/mockData';

const TrainingHistory: React.FC = () => {
  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);

    if (date.toDateString() === today.toDateString()) {
      return '今天';
    } else if (date.toDateString() === yesterday.toDateString()) {
      return '昨天';
    } else {
      return date.toLocaleDateString('zh-CN', { month: 'long', day: 'numeric' });
    }
  };

  const groupedRecords = workoutRecords.reduce((acc, record) => {
    const date = formatDate(record.date);
    if (!acc[date]) {
      acc[date] = [];
    }
    acc[date].push(record);
    return acc;
  }, {} as Record<string, typeof workoutRecords>);

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <div className="bg-gradient-to-br from-cyan-500 to-cyan-600 text-white px-4 pt-8 pb-16">
        <div className="max-w-md mx-auto">
          <h1 className="text-2xl font-bold mb-1">训练记录</h1>
          <p className="text-cyan-100">查看你的运动历程</p>
        </div>
      </div>

      <div className="px-4 -mt-8">
        <div className="max-w-md mx-auto">
          <div className="bg-white rounded-2xl p-6 shadow-lg mb-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-cyan-100 rounded-full flex items-center justify-center">
                  <Calendar className="w-6 h-6 text-cyan-600" />
                </div>
                <div>
                  <p className="text-3xl font-bold text-gray-800">{workoutRecords.length}</p>
                  <p className="text-sm text-gray-500">总训练次数</p>
                </div>
              </div>
              <div className="text-right">
                <p className="text-2xl font-bold text-orange-500">
                  {workoutRecords.reduce((sum, r) => sum + r.calories, 0)}
                </p>
                <p className="text-sm text-gray-500">总消耗千卡</p>
              </div>
            </div>
          </div>

          <div className="space-y-6">
            {Object.entries(groupedRecords).map(([date, records]) => (
              <div key={date}>
                <h2 className="text-sm font-medium text-gray-500 mb-3">{date}</h2>
                <div className="space-y-3">
                  {records.map((record) => (
                    <div
                      key={record.id}
                      className="bg-white rounded-xl p-4 shadow-sm border border-gray-100 flex items-center gap-4"
                    >
                      <div className="w-12 h-12 bg-green-100 rounded-full flex items-center justify-center flex-shrink-0">
                        <CheckCircle2 className="w-6 h-6 text-green-600" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <h3 className="font-medium text-gray-800 truncate">
                          {record.courseTitle}
                        </h3>
                        <div className="flex items-center gap-4 mt-1">
                          <div className="flex items-center gap-1 text-sm text-gray-500">
                            <Clock className="w-4 h-4" />
                            <span>{record.duration}</span>
                          </div>
                          <div className="flex items-center gap-1 text-sm text-gray-500">
                            <Flame className="w-4 h-4" />
                            <span>{record.calories}千卡</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

          {workoutRecords.length === 0 && (
            <div className="text-center py-16">
              <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <Calendar className="w-10 h-10 text-gray-400" />
              </div>
              <p className="text-gray-500 mb-2">还没有训练记录</p>
              <p className="text-sm text-gray-400">开始你的第一次训练吧！</p>
            </div>
          )}
        </div>
      </div>

      <BottomNav />
    </div>
  );
};

export default TrainingHistory;
