import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  Pause,
  Play,
  SkipForward,
  Volume2,
  CheckCircle2,
  X,
} from 'lucide-react';
import { courses } from '../data/mockData';

const Workout: React.FC = () => {
  const navigate = useNavigate();
  const [isPlaying, setIsPlaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(60);
  const [currentExerciseIndex, setCurrentExerciseIndex] = useState(0);
  const [progress, setProgress] = useState(0);

  const course = courses[0];
  const exercises = course.exercises;
  const currentExercise = exercises[currentExerciseIndex];

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isPlaying && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && currentExerciseIndex < exercises.length - 1) {
      handleNext();
    }
    return () => clearInterval(interval);
  }, [isPlaying, timeLeft, currentExerciseIndex]);

  const handleNext = () => {
    if (currentExerciseIndex < exercises.length - 1) {
      setCurrentExerciseIndex((prev) => prev + 1);
      setTimeLeft(60);
      setProgress(((currentExerciseIndex + 1) / exercises.length));
    } else {
      navigate('/history');
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const circumference = 2 * Math.PI * 80;
  const strokeDashoffset = circumference - (progress * circumference);

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-900 to-gray-800 text-white">
      <div className="relative h-96">
        <img
          src={currentExercise.image}
          alt={currentExercise.name}
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-gray-900 via-gray-900/50 to-transparent" />
        <div className="absolute top-6 left-4 right-4">
          <div className="max-w-md mx-auto flex items-center justify-between">
            <button
              onClick={() => navigate(-1)}
              className="p-2 bg-white/10 backdrop-blur rounded-full"
            >
              <X className="w-6 h-6" />
            </button>
            <div className="flex gap-2">
              <button className="p-2 bg-white/10 backdrop-blur rounded-full">
                <Volume2 className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="px-4 -mt-40 relative z-10">
        <div className="max-w-md mx-auto">
        <div className="text-center mb-8">
          <p className="text-cyan-400 text-sm font-medium mb-2">
            {currentExerciseIndex + 1} / {exercises.length}
          </p>
          <h1 className="text-3xl font-bold mb-1">{currentExercise.name}</h1>
          <p className="text-gray-400">
            {currentExercise.reps ? `${currentExercise.reps}次` : currentExercise.duration}
          </p>
        </div>

        <div className="flex justify-center mb-8">
          <div className="relative">
            <svg className="w-48 h-48 transform -rotate-90">
              <circle
                cx="96"
                cy="96"
                r="80"
                stroke="#374151"
                strokeWidth="12"
                fill="none"
              />
              <circle
                cx="96"
                cy="96"
                r="80"
                stroke="#22d3ee"
                strokeWidth="12"
                fill="none"
                strokeLinecap="round"
                strokeDasharray={circumference}
                strokeDashoffset={strokeDashoffset}
                className="transition-all duration-300"
              />
            </svg>
            <div className="absolute inset-0 flex items-center justify-center">
              <span className="text-5xl font-bold">{formatTime(timeLeft)}</span>
            </div>
          </div>
        </div>

        <div className="flex justify-center gap-6 mb-8">
          <button
            onClick={() => setIsPlaying(!isPlaying)}
            className="w-20 h-20 bg-cyan-500 rounded-full flex items-center justify-center shadow-lg shadow-cyan-500/50 hover:bg-cyan-400 transition-colors"
          >
            {isPlaying ? (
              <Pause className="w-10 h-10 fill-current" />
            ) : (
              <Play className="w-10 h-10 fill-current ml-1" />
            )}
          </button>
          <button
            onClick={handleNext}
            className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center hover:bg-white/20 transition-colors"
          >
            <SkipForward className="w-8 h-8" />
          </button>
        </div>

        {currentExerciseIndex < exercises.length - 1 && (
          <div className="bg-white/10 backdrop-blur rounded-2xl p-4 mb-6">
            <p className="text-gray-400 text-sm mb-2">下一个动作</p>
            <div className="flex items-center gap-4">
              <img
                src={exercises[currentExerciseIndex + 1].image}
                alt={exercises[currentExerciseIndex + 1].name}
                className="w-16 h-16 rounded-xl object-cover"
              />
              <div>
                <h3 className="font-medium">
                  {exercises[currentExerciseIndex + 1].name}
                </h3>
                <p className="text-sm text-gray-400">
                  {exercises[currentExerciseIndex + 1].duration}
                </p>
              </div>
            </div>
          </div>
        )}

        {currentExerciseIndex === exercises.length - 1 && timeLeft <= 10 && (
          <div className="text-center">
            <div className="inline-flex items-center gap-2 text-green-400 mb-4">
              <CheckCircle2 className="w-6 h-6" />
              <span className="font-medium">快要完成了！</span>
            </div>
          </div>
        )}
      </div>
      </div>
    </div>
  );
};

export default Workout;
