import React from 'react';

interface StatCardProps {
  value: string | number;
  label: string;
  color?: 'cyan' | 'orange' | 'purple' | 'green';
  icon?: React.ReactNode;
  variant?: 'default' | 'white';
}

const StatCard: React.FC<StatCardProps> = ({
  value,
  label,
  color = 'cyan',
  icon,
  variant = 'default',
}) => {
  const isWhite = variant === 'white';
  
  const colorClasses = {
    cyan: isWhite ? 'text-cyan-500' : '',
    orange: isWhite ? 'text-orange-500' : '',
    purple: isWhite ? 'text-purple-500' : '',
    green: isWhite ? 'text-green-500' : '',
  };

  return (
    <div className={`${isWhite ? 'bg-white/20' : 'bg-white'} rounded-2xl p-4 ${isWhite ? '' : 'shadow-sm border border-gray-100'}`}>
      <div className="flex items-center justify-between">
        <div>
          <p className={`text-2xl font-bold ${isWhite ? 'text-white' : 'text-gray-800'}`}>{value}</p>
          <p className={`text-sm ${isWhite ? 'text-cyan-100' : 'text-gray-500'} mt-1`}>{label}</p>
        </div>
        {icon && (
          <div className={`p-3 rounded-xl ${isWhite ? 'bg-white/20' : 'bg-gray-100'}`}>
            <div className={colorClasses[color]}>{icon}</div>
          </div>
        )}
      </div>
    </div>
  );
};

export default StatCard;
