import React from 'react';
import { Link } from 'react-router-dom';
import { Clock, Flame, Star } from 'lucide-react';
import { Course } from '../data/mockData';

interface CourseCardProps {
  course: Course;
}

const CourseCard: React.FC<CourseCardProps> = ({ course }) => {
  const difficultyColors = {
    beginner: 'bg-green-100 text-green-700',
    intermediate: 'bg-yellow-100 text-yellow-700',
    advanced: 'bg-red-100 text-red-700',
  };

  const difficultyLabels = {
    beginner: '初级',
    intermediate: '中级',
    advanced: '高级',
  };

  return (
    <Link
      to={`/courses/${course.id}`}
      className="bg-white rounded-2xl overflow-hidden shadow-sm border border-gray-100 hover:shadow-md transition-shadow"
    >
      <div className="relative">
        <img
          src={course.image}
          alt={course.title}
          className="w-full h-40 object-cover"
        />
        <div className="absolute top-3 left-3">
          <span
            className={`px-3 py-1 rounded-full text-xs font-medium ${difficultyColors[course.difficulty]}`}
          >
            {difficultyLabels[course.difficulty]}
          </span>
        </div>
        {course.price && (
          <div className="absolute top-3 right-3 bg-white px-3 py-1 rounded-full">
            <span className="text-cyan-600 font-bold text-sm">¥{course.price}</span>
          </div>
        )}
      </div>
      <div className="p-4">
        <h3 className="font-bold text-gray-800 mb-2">{course.title}</h3>
        <p className="text-sm text-gray-500 mb-3 line-clamp-2">{course.description}</p>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-1 text-sm text-gray-500">
              <Clock className="w-4 h-4" />
              <span>{course.duration}</span>
            </div>
            <div className="flex items-center gap-1 text-sm text-gray-500">
              <Flame className="w-4 h-4" />
              <span>{course.calories}千卡</span>
            </div>
          </div>
          <div className="flex items-center gap-1">
            <Star className="w-4 h-4 text-yellow-400 fill-yellow-400" />
            <span className="text-sm font-medium">{course.rating}</span>
          </div>
        </div>
      </div>
    </Link>
  );
};

export default CourseCard;
